def main():
    print(f"开始导入 {len(CASES)} 个测试用例到禅道...")
    print("-" * 50)
    
    success_count = 0
    fail_count = 0
    
    for tc_id, pri, story_id, title, steps in CASES:
        # 构建步骤
        formatted_steps = []
        for desc, expect in steps:
            if expect:
                formatted_steps.append({"desc": desc, "expect": expect})
            else:
                formatted_steps.append({"desc": desc, "expect": ""})
        
        data = {
            "title": f"【{tc_id}】{title}",
            "pri": pri,
            "type": "feature",
            "story": story_id,
            "steps": formatted_steps
        }
        
        response = api_post(f"products/{PRODUCT_ID}/testcases", data)
        
        if "id" in response:
            print(f"✓ {tc_id} -> ID: {response['id']}")
            success_count += 1
        else:
            print(f"✗ {tc_id} -> 失败: {response.get('error', 'Unknown error')[:100]}")
            fail_count += 1
    
    print("-" * 50)
    print(f"导入完成: 成功 {success_count}, 失败 {fail_count}")

if __name__ == "__main__":
    main()
